.darma-loader-uiverse-pearl-typing-row { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-pearl-typing-row__wrapper {
  position: relative;
  width: 220px;
  height: 110px;
  display: flex;
  justify-content: center;
  align-items: center;
}

.darma-loader-uiverse-pearl-typing-row__circle-loader {
display: flex;
gap: 15px;
}

.darma-loader-uiverse-pearl-typing-row__circle {
width: 24px;
height: 24px;
border-radius: 50%;
background: radial-gradient(circle at 30% 30%, #f5f5f5, var(--loader-color, #d5d5d5));
position: relative;
box-shadow:
6px 6px 12px rgba(0, 0, 0, 0.15),
-6px -6px 12px color-mix(in srgb, var(--loader-secondary-color, #ffffff) 80%, transparent),
inset 2px 2px 4px rgba(0, 0, 0, 0.1),
inset -2px -2px 4px color-mix(in srgb, var(--loader-secondary-color, #ffffff) 90%, transparent);
animation: darma-loader-uiverse-pearl-typing-row-circleRotate 2s ease-in-out infinite;
}

.darma-loader-uiverse-pearl-typing-row__circle:nth-child(1) {
animation-delay: 0s;
}

.darma-loader-uiverse-pearl-typing-row__circle:nth-child(2) {
animation-delay: 0.2s;
}

.darma-loader-uiverse-pearl-typing-row__circle:nth-child(3) {
animation-delay: 0.3s;
}

.darma-loader-uiverse-pearl-typing-row__circle:nth-child(4) {
animation-delay: 0.4s;
}

.darma-loader-uiverse-pearl-typing-row__circle:nth-child(5) {
animation-delay: 0.5s;
}

.darma-loader-uiverse-pearl-typing-row__circle:nth-child(6) {
animation-delay: 0.6s;
}

.darma-loader-uiverse-pearl-typing-row__circle:nth-child(7) {
animation-delay: 0.7s;
}

.darma-loader-uiverse-pearl-typing-row__circle::before {
content: "";
position: absolute;
top: 8px;
left: 8px;
width: 15px;
height: 15px;
background: radial-gradient(circle, color-mix(in srgb, var(--loader-secondary-color, #ffffff) 80%, transparent), transparent);
border-radius: 50%;
}

@keyframes darma-loader-uiverse-pearl-typing-row-circleRotate {
0% {
transform: scale(1) rotateZ(0deg);
box-shadow:
6px 6px 12px rgba(0, 0, 0, 0.15),
-6px -6px 12px color-mix(in srgb, var(--loader-secondary-color, #ffffff) 80%, transparent),
inset 2px 2px 4px rgba(0, 0, 0, 0.1),
inset -2px -2px 4px color-mix(in srgb, var(--loader-secondary-color, #ffffff) 90%, transparent);
}

50% {
transform: scale(1.2) rotateZ(180deg);
box-shadow:
8px 8px 16px rgba(0, 0, 0, 0.2),
-8px -8px 16px color-mix(in srgb, var(--loader-secondary-color, #ffffff) 90%, transparent),
inset 3px 3px 6px rgba(0, 0, 0, 0.15),
inset -3px -3px 6px var(--loader-secondary-color, #ffffff);
}

100% {
transform: scale(1) rotateZ(360deg);
box-shadow:
6px 6px 12px rgba(0, 0, 0, 0.15),
-6px -6px 12px color-mix(in srgb, var(--loader-secondary-color, #ffffff) 80%, transparent),
inset 2px 2px 4px rgba(0, 0, 0, 0.1),
inset -2px -2px 4px color-mix(in srgb, var(--loader-secondary-color, #ffffff) 90%, transparent);
}
}

.darma-loader-uiverse-pearl-typing-row__loading-text {
position: absolute;
bottom: 30px;
left: 50%;
transform: translateX(-50%);
font-size: 24px;
font-weight: 300;
color: #444;
letter-spacing: 1px;
animation: darma-loader-uiverse-pearl-typing-row-fadeBlink 1.5s infinite;
}

@keyframes darma-loader-uiverse-pearl-typing-row-fadeBlink {
0%,
100% {
opacity: 1;
transform: translateX(-50%) translateY(0);
}

50% {
opacity: 0.4;
transform: translateX(-50%) translateY(-3px);
}
}

